import React from "react";


import Buttons from "../button/button";
import "./sidebar_style.css";
import { FaAngleDoubleLeft, FaAngleDoubleRight } from "react-icons/fa";
const Sidebar = ({image,collapsed,toggled,handleToggleSidebar,HandleCollapsedChange}) => {
            return (
            <>
            <ProSidebar
                        image={image}
                        collapsed={collapsed}
                        toggled={toggled}
                        breakPoint="md"
                        onToggle={handleToggleSidebar}
                        onCollapse={HandleCollapsedChange}

            >
                        <SidebarHeader>
                             <Menu iconShape="circle" >
                                    {collapsed ?(
                                                <MenuItem
                                                icon={<FaAngleDoubleRight/>}
                                                onClick={HandleCollapsedChange}
                                                ></MenuItem>
                                    ):(
                                                <MenuItem
                                                suffix={<FaAngleDoubleLeft/>}
                                                onClick={HandleCollapsedChange}
                                                >

                                                <div style={{
                                                            padding: "9px",
                                                            textTransform: "uppercase",
                                                            fontWeight: "bold",
                                                            fontSize: 15,
                                                            letterSpacing: "1px",
                                                }}  >
                                                            Admin Dashboard
                                                </div>  
                                                            </MenuItem>
                                         )};
                                    </Menu>
                        </SidebarHeader>

                        <SidebarContent>

                         </SidebarContent>
                        <SidebarFooter>

                        </SidebarFooter>

            </ProSidebar>
            <div className="sidebar">

                        <div className="side_list">
                                    <Buttons value="Dashboard" />
                                    <Buttons value="Users" />
                                    <Buttons value="Products" />
                                    <Buttons value="Transactions" />
                                    <Buttons value="Reports" />
                                    <Buttons value="Manage" />
                                    <Buttons value="Settings" />
                                    <Buttons value="Logout" />

                        </div>
                        <div className="profile">
                                    <img  className="profile_img" src="" alt=""  />
                                    <p className="profile_name">John Doe</p>
                        </div>
                        </div>

            </>
            );
            }

export default Sidebar;
